const data = $input.item.json;

// Определение направления текста (RTL/LTR)
const rtlLanguages = ['arabic', 'hebrew', 'persian', 'urdu'];
const currentLang = data.language ? data.language.toLowerCase() : 'english';
const isRtl = rtlLanguages.some(lang => currentLang.includes(lang));

const direction = isRtl ? 'rtl' : 'ltr';
const textAlign = isRtl ? 'right' : 'left';
const borderSide = isRtl ? 'right' : 'left';

const htmlContent = `
<!DOCTYPE html>
<html dir="${direction}">
<head>
    <meta charset="UTF-8">
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Roboto:wght@300;400;700&display=swap');

        @page { size: A4; margin: 0; }
        body { 
            font-family: 'Roboto', Arial, sans-serif; 
            direction: ${direction}; 
            text-align: ${textAlign}; 
            color: #333; 
            line-height: 1.5; 
            margin: 0; padding: 0;
            background-color: #ffffff;
        }
        .page { 
            width: 210mm; height: 296mm;
            padding: 25mm 20mm; 
            page-break-after: always; 
            box-sizing: border-box;
            position: relative;
        }

        /* Титульный лист */
        .cover-page {
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            background-color: #f4f7f9; /* Легкий фон для титульника */
        }
        .cover-title { font-size: 32pt; font-weight: 700; color: #2c3e50; margin-bottom: 10px; text-transform: uppercase; }
        .cover-subtitle { font-size: 20pt; color: #7f8c8d; margin-bottom: 50px; }
        .cover-contact { font-size: 12pt; border-top: 2px solid #2c3e50; padding-top: 20px; text-align: center; }

        /* Заголовки */
        .section-title { 
            font-size: 14pt; font-weight: 700; color: #2c3e50; 
            background-color: #f8f9fa;
            padding: 5px 10px;
            border-${borderSide}: 5px solid #2c3e50;
            margin-top: 20px; margin-bottom: 15px; 
            text-transform: uppercase; 
            letter-spacing: 1px;
        }

        /* Таблицы структуры */
        .cv-table { width: 100%; border-collapse: collapse; margin-bottom: 15px; }
        .cv-table td { padding: 10px 0; vertical-align: top; }
        .date-col { width: 28%; font-weight: 700; color: #2c3e50; font-size: 10.5pt; }
        .content-col { width: 72%; padding-${borderSide}: 15px; }

        .job-title { font-size: 11pt; font-weight: 700; color: #34495e; }
        .company-name { font-size: 10pt; color: #2980b9; font-weight: 400; margin-bottom: 5px; display: block; }

        /* Полоски навыков */
        .skill-item { margin-bottom: 10px; display: flex; align-items: center; }
        .skill-name { width: 130px; font-weight: 700; font-size: 10pt; color: #2c3e50; }
        .skill-bar-bg { background: #ecf0f1; flex-grow: 1; height: 8px; border-radius: 4px; margin: 0 15px; }
        .skill-bar-fill { height: 100%; background: #2c3e50; border-radius: 4px; }

        /* Личные данные в шапке */
        .header-info { 
            display: flex; justify-content: space-between; 
            font-size: 9pt; color: #7f8c8d; margin-bottom: 20px;
            border-bottom: 1px solid #eee; padding-bottom: 10px;
        }

        .qualities-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; }
        .quality-item { margin-bottom: 10px; }
        .quality-name { font-weight: 700; color: #2c3e50; display: block; margin-bottom: 3px; }
        .quality-desc { font-size: 9.5pt; color: #666; line-height: 1.3; }

        ul { margin: 5px 0; padding-${isRtl ? 'right' : 'left'}: 15px; font-size: 10pt; color: #444; }
        li { margin-bottom: 4px; }
    </style>
</head>
<body>

    <div class="page cover-page">
        <div class="cover-title">${data.name}</div>
        <div class="cover-subtitle">${data.target_position}</div>
        <div class="cover-contact">
            <p>${data.email} | ${data.phone}</p>
            <p>${data.address}</p>
            <p>${data.labels.citizenship}: ${data.citizenship} | ${data.labels.birth_date}: ${data.birth_date}</p>
        </div>
    </div>

    <div class="page">
        <div class="section-title">${data.labels.letter}</div>
        <div style="margin-top: 30px; font-size: 11pt; color: #7f8c8d; text-align: ${isRtl ? 'left' : 'right'};">
            ${new Date().toLocaleDateString(data.language)}
        </div>
        <div style="margin-top: 40px; font-size: 11.5pt; text-align: justify; line-height: 1.7;">
            ${data.cover_letter_text.replace(/\n/g, '<br>')}
        </div>
        <div style="margin-top: 50px; font-weight: 700;">
            ${data.name}
        </div>
    </div>

    <div class="page">
        <div class="header-info">
            <span>${data.email}</span>
            <span>${data.phone}</span>
            <span>${data.address}</span>
        </div>

        <div class="section-title">${data.labels.experience}</div>
        <table class="cv-table">
            ${data.experience.map(exp => `
                <tr>
                    <td class="date-col">${exp.period}</td>
                    <td class="content-col">
                        <div class="job-title">${exp.position}</div>
                        <span class="company-name">${exp.company}</span>
                        <ul>${exp.tasks.map(t => `<li>${t}</li>`).join('')}</ul>
                    </td>
                </tr>
            `).join('')}
        </table>

        <div class="section-title">${data.labels.education}</div>
        <table class="cv-table">
            ${data.education.map(edu => `
                <tr>
                    <td class="date-col">${edu.edu_period}</td>
                    <td class="content-col">
                        <div class="job-title">${edu.institution}</div>
                        <div style="font-size: 10pt;">${edu.specialization}</div>
                    </td>
                </tr>
            `).join('')}
        </table>

        <div class="section-title">${data.labels.qualities}</div>
        <div class="qualities-grid">
            ${data.strengths.map(s => `
                <div class="quality-item">
                    <span class="quality-name">${s.quality}</span>
                    <span class="quality-desc">${s.description}</span>
                </div>
            `).join('')}
        </div>

        <div class="section-title">${data.labels.skills}</div>
        ${data.languages.map(l => `
            <div class="skill-item">
                <div class="skill-name">${l.lang}</div>
                <div class="skill-bar-bg"><div class="skill-bar-fill" style="width: ${l.value}%;"></div></div>
                <div style="width: 50px; font-size: 9pt; font-weight: 700;">${l.level}</div>
            </div>
        `).join('')}

        <div class="section-title">${data.labels.it} & ${data.labels.driving}</div>
        <div style="font-size: 10pt; color: #444;">
            <strong>IT:</strong> ${data.it_skills}<br>
            <strong>${data.labels.driving}:</strong> ${data.driving_license}
        </div>
    </div>

</body>
</html>
`;

return { html: htmlContent };
